#include<bits/stdc++.h>
using namespace std;
int a[10001],dp[10001];
int main()
{
    int n,k;
    scanf("%d%d",&n,&k);
    for(int i=1;i<=k;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=k;j++)
        {
            if(i<a[j])
            {
                continue;
            }
            dp[i]=max(dp[i],i-dp[i-a[j]]);
        }
    }
    printf("%d",dp[n]);
    return 0;
}
